import{_ as e,o as r,c as t,a3 as n}from"./chunks/framework.q4B3G9ZH.js";const h=JSON.parse('{"title":"辐射度量学","description":"","frontmatter":{},"headers":[],"relativePath":"图形学/games101/raytracing.md","filePath":"图形学/games101/raytracing.md","lastUpdated":null}'),i={name:"图形学/games101/raytracing.md"};function s(d,a,c,l,g,m){return r(),t("div",null,[...a[0]||(a[0]=[n('<h1 id="辐射度量学" tabindex="-1">辐射度量学 <a class="header-anchor" href="#辐射度量学" aria-label="Permalink to &quot;辐射度量学&quot;">​</a></h1><p>引入原因：用物理方法精确的描述光。 在物理上准确的定义光照。</p><h2 id="radiant-energy-and-flux" tabindex="-1">Radiant Energy and Flux <a class="header-anchor" href="#radiant-energy-and-flux" aria-label="Permalink to &quot;Radiant Energy and Flux&quot;">​</a></h2><p><img src="https://cdn.jsdelivr.net/gh/xumyuan/image@master/blogs/pictures20230301190422.png" alt="20230301190422"> radiant energy：即光的能量 flux：为单位时间内的光的能量，即光的功率。给定区域单位时间通过光子的量。 在图形学中多半会使用单位时间的能量，而非实际的能量。</p><h2 id="radiant-intensity" tabindex="-1">Radiant Intensity <a class="header-anchor" href="#radiant-intensity" aria-label="Permalink to &quot;Radiant Intensity&quot;">​</a></h2><p><img src="https://cdn.jsdelivr.net/gh/xumyuan/image@master/blogs/pictures20230301190736.png" alt="20230301190736"> 定义：每一个单位立体角的能量。 角度的定义为弧长除以半径，立体角为角度在三维空间的延申，为面积除以半径的平方 <img src="https://cdn.jsdelivr.net/gh/xumyuan/image@master/blogs/pictures20230301190941.png" alt="20230301190941"> 单位立体角（微分立体角）θ和φ微小变化时，立体角的变化。 <img src="https://cdn.jsdelivr.net/gh/xumyuan/image@master/blogs/pictures20230301191152.png" alt="20230301191152"></p><h2 id="irradiance" tabindex="-1">Irradiance <a class="header-anchor" href="#irradiance" aria-label="Permalink to &quot;Irradiance&quot;">​</a></h2><p><img src="https://cdn.jsdelivr.net/gh/xumyuan/image@master/blogs/pictures20230301192641.png" alt="20230301192641"> 定义：每一个单位面积的能量，垂直于面的能量（不垂直情况需要投影变换）。 光线随距离衰减实际上是irradiance的衰减。 <img src="https://cdn.jsdelivr.net/gh/xumyuan/image@master/blogs/pictures20230302200757.png" alt="20230302200757"></p><h2 id="radiance" tabindex="-1">Radiance <a class="header-anchor" href="#radiance" aria-label="Permalink to &quot;Radiance&quot;">​</a></h2><p><img src="https://cdn.jsdelivr.net/gh/xumyuan/image@master/blogs/pictures20230302200900.png" alt="20230302200900"> 定义：光在单位立体角单位面积上的能量。 联系irradiance和intensity，irradiance即： 单位立体角上的radiance； 单位面积上的intensity。 <strong>看到的是radiance</strong></p><h2 id="irradiance和radiance" tabindex="-1">Irradiance和Radiance <a class="header-anchor" href="#irradiance和radiance" aria-label="Permalink to &quot;Irradiance和Radiance&quot;">​</a></h2><p><img src="https://cdn.jsdelivr.net/gh/xumyuan/image@master/blogs/pictures20230302201630.png" alt="20230302201630"> irradiance是单位面积接受来自各个方向上的能量，radiance是单位面积在单位立体角度上接受的能量。</p><h2 id="brdf" tabindex="-1">BRDF <a class="header-anchor" href="#brdf" aria-label="Permalink to &quot;BRDF&quot;">​</a></h2><p><img src="https://cdn.jsdelivr.net/gh/xumyuan/image@master/blogs/pictures20230302202146.png" alt="20230302202146"> 定义一个单位面积收到的irradiance和反射radiance的比例。 描述光线和物体的作用，跟材质相关。</p><h2 id="反射方程" tabindex="-1">反射方程 <a class="header-anchor" href="#反射方程" aria-label="Permalink to &quot;反射方程&quot;">​</a></h2><p><img src="https://cdn.jsdelivr.net/gh/xumyuan/image@master/blogs/pictures20230302202747.png" alt="20230302202747"> 上为物体不发光，下为物体自身会发光。 fr为BRDF</p><h2 id="rendering-equation" tabindex="-1">Rendering Equation <a class="header-anchor" href="#rendering-equation" aria-label="Permalink to &quot;Rendering Equation&quot;">​</a></h2><p><img src="https://cdn.jsdelivr.net/gh/xumyuan/image@master/blogs/pictures20230302203149.png" alt="20230302203149"> 点光源情况，面光源即为点光源相加。 <img src="https://cdn.jsdelivr.net/gh/xumyuan/image@master/blogs/pictures20230302203403.png" alt="20230302203403"> 已知为物体材质，自身发光状况。未知为物体接受各种光的irradiance和反射出去的radiance。 方程简写（写成算子的形式）： <img src="https://cdn.jsdelivr.net/gh/xumyuan/image@master/blogs/pictures20230302203555.png" alt="20230302203555"><img src="https://cdn.jsdelivr.net/gh/xumyuan/image@master/blogs/pictures20230302203639.png" alt="20230302203639"> 光线直射、弹射一次、两次、三次... <img src="https://cdn.jsdelivr.net/gh/xumyuan/image@master/blogs/pictures20230302203812.png" alt="20230302203812"></p>',18)])])}const o=e(i,[["render",s]]);export{h as __pageData,o as default};
